M_.det_shocks = [ M_.det_shocks;
struct('exo_det',false,'exo_id',1,'type','level','periods',1:1,'value',0.01);
struct('exo_det',false,'exo_id',2,'type','level','periods',5:8,'value',0.005);
struct('exo_det',false,'exo_id',3,'type','level','periods',1:10,'value',0.02);
];
